-- Name: log_audit_event(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_audit_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    audit_user_id UUID := NULL;
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO audit_log (user_id, action, table_name, record_id, new_data, created_at, updated_at)
        VALUES (audit_user_id, 'CREATE', TG_TABLE_NAME, NEW.id, to_jsonb(NEW), CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        INSERT INTO audit_log (user_id, action, table_name, record_id, old_data, new_data, created_at, updated_at)
        VALUES (audit_user_id, 'UPDATE', TG_TABLE_NAME, NEW.id, to_jsonb(OLD), to_jsonb(NEW), CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        INSERT INTO audit_log (user_id, action, table_name, record_id, old_data, created_at, updated_at)
        VALUES (audit_user_id, 'DELETE', TG_TABLE_NAME, OLD.id, to_jsonb(OLD), CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
        RETURN OLD;
    END IF;
END;
$$;


ALTER FUNCTION public.log_audit_event() OWNER TO postgres;

